let mergedArray = [];

for (let i = 0; i < items.length; i++) {
    const itemData = items[i].json;

    if (Array.isArray(itemData)) {
        mergedArray.push(...itemData);
    } else {
        mergedArray.push(itemData);
    }
}

return [{
    json: {
        merged: mergedArray,
        totalRecords: mergedArray.length
    }
}];

